"use client"

import { type VariantProps } from "class-variance-authority"
import { FollowButtonUI, followButtonVariants } from "./ui"
import {
  useFollow,
  type FollowResult,
  type FollowState,
  type UseFollowReturn,
  type UseFollowOptions,
} from "./use-follow"

// ---------------------------------------------------------------------------
// Re-exports
// ---------------------------------------------------------------------------

export {
  FollowButtonUI,
  followButtonVariants,
  type FollowButtonUIProps,
} from "./ui"
export {
  useFollow,
  type FollowResult,
  type FollowState,
  type UseFollowReturn,
  type UseFollowOptions,
} from "./use-follow"

// ---------------------------------------------------------------------------
// Types
// ---------------------------------------------------------------------------

export interface FollowButtonProps
  extends VariantProps<typeof followButtonVariants> {
  /** Additional CSS classes */
  className?: string
  /** BAP identity key of the user to follow */
  bapId: string
  /** Whether the current user is already following this user */
  isFollowing?: boolean
  /** Called to broadcast a follow action */
  onFollow: (bapId: string) => Promise<FollowResult>
  /** Called to broadcast an unfollow action */
  onUnfollow?: (bapId: string) => Promise<FollowResult>
  /** Called after a successful follow/unfollow */
  onToggled?: (following: boolean, result: FollowResult) => void
  /** Called on error */
  onError?: (error: Error) => void
  /** Disable the button */
  disabled?: boolean
  /** Labels for the three visual states */
  labels?: {
    follow?: string
    following?: string
    unfollow?: string
  }
}

// ---------------------------------------------------------------------------
// Composed component
// ---------------------------------------------------------------------------

/**
 * A follow/unfollow toggle button for BSocial identities.
 *
 * Renders three visual states:
 * - **Follow** (idle) -- primary CTA to follow a user
 * - **Following** (confirmed) -- subdued indicator that the user is followed
 * - **Unfollow** (hover on "Following") -- destructive action on hover
 *
 * Delegates transaction building to `onFollow`/`onUnfollow` callbacks.
 *
 * @example
 * ```tsx
 * import { FollowButton } from "@/components/blocks/follow-button"
 *
 * <FollowButton
 *   bapId="02abc..."
 *   isFollowing={false}
 *   onFollow={async (bapId) => {
 *     // build BSocial follow tx
 *     return { txid: "abc123..." }
 *   }}
 * />
 * ```
 */
export function FollowButton({
  variant = "default",
  className,
  bapId,
  isFollowing = false,
  onFollow,
  onUnfollow,
  onToggled,
  onError,
  disabled = false,
  labels = {},
}: FollowButtonProps) {
  const hook = useFollow({
    bapId,
    isFollowing,
    onFollow,
    onUnfollow,
    onToggled,
    onError,
    labels,
  })

  return (
    <FollowButtonUI
      variant={variant}
      className={className}
      bapId={bapId}
      following={hook.following}
      showUnfollow={hook.showUnfollow}
      isLoading={hook.isLoading}
      currentLabel={hook.currentLabel}
      onClick={hook.handleClick}
      onMouseEnter={() => hook.setIsHovering(true)}
      onMouseLeave={() => hook.setIsHovering(false)}
      disabled={disabled}
    />
  )
}

"use client"

import { cva, type VariantProps } from "class-variance-authority"
import { cn } from "@/lib/utils"
import { Button } from "@/components/ui/button"
import { Loader2, UserMinus, UserPlus } from "lucide-react"

// ---------------------------------------------------------------------------
// Variant definitions
// ---------------------------------------------------------------------------

export const followButtonVariants = cva(
  "inline-flex items-center justify-center gap-2 font-medium transition-all",
  {
    variants: {
      variant: {
        default: "rounded-md px-4 py-2 text-sm shadow-sm",
        compact: "rounded-md px-3 py-1.5 text-xs shadow-sm",
        pill: "rounded-full px-5 py-2 text-sm shadow-sm",
      },
    },
    defaultVariants: {
      variant: "default",
    },
  },
)

// ---------------------------------------------------------------------------
// Types
// ---------------------------------------------------------------------------

export interface FollowButtonUIProps
  extends VariantProps<typeof followButtonVariants> {
  /** Additional CSS classes */
  className?: string
  /** BAP identity key of the user (for aria-label) */
  bapId: string
  /** Whether the current user is following the target */
  following: boolean
  /** Whether the unfollow UI should show (hover state) */
  showUnfollow: boolean
  /** Whether a follow/unfollow action is in progress */
  isLoading: boolean
  /** The current label to display */
  currentLabel: string
  /** Handle the follow/unfollow click */
  onClick: () => void
  /** Handle mouse enter */
  onMouseEnter: () => void
  /** Handle mouse leave */
  onMouseLeave: () => void
  /** Disable the button */
  disabled?: boolean
}

// ---------------------------------------------------------------------------
// Component
// ---------------------------------------------------------------------------

export function FollowButtonUI({
  variant = "default",
  className,
  bapId,
  following,
  showUnfollow,
  isLoading,
  currentLabel,
  onClick,
  onMouseEnter,
  onMouseLeave,
  disabled = false,
}: FollowButtonUIProps) {
  return (
    <Button
      variant="ghost"
      size={variant === "compact" ? "sm" : "default"}
      className={cn(
        followButtonVariants({ variant }),
        // Follow state (not following)
        !following &&
          "bg-primary text-primary-foreground hover:bg-primary/90",
        // Following state (no hover)
        following &&
          !showUnfollow &&
          "border border-input bg-background text-foreground hover:bg-accent/50",
        // Unfollow state (hover while following)
        showUnfollow &&
          "border border-destructive/30 bg-destructive/5 text-destructive hover:bg-destructive/10",
        className,
      )}
      onClick={onClick}
      onMouseEnter={onMouseEnter}
      onMouseLeave={onMouseLeave}
      disabled={disabled || isLoading}
      aria-label={following ? `Unfollow ${bapId}` : `Follow ${bapId}`}
      aria-pressed={following}
    >
      {isLoading ? (
        <Loader2 className="animate-spin" data-icon="inline-start" aria-hidden="true" />
      ) : showUnfollow ? (
        <UserMinus data-icon="inline-start" aria-hidden="true" />
      ) : !following ? (
        <UserPlus data-icon="inline-start" aria-hidden="true" />
      ) : null}
      <span>{currentLabel}</span>
    </Button>
  )
}

import { useCallback, useState } from "react"

// ---------------------------------------------------------------------------
// Types
// ---------------------------------------------------------------------------

export type FollowState = "idle" | "following" | "unfollowing"

export interface FollowResult {
  /** Transaction ID of the follow/unfollow action */
  txid?: string
  /** Raw transaction hex */
  rawtx?: string
  /** Error message if the action failed */
  error?: string
}

export interface UseFollowOptions {
  /** BAP identity key of the user to follow */
  bapId: string
  /** Whether the current user is already following this user */
  isFollowing?: boolean
  /** Called to broadcast a follow action */
  onFollow: (bapId: string) => Promise<FollowResult>
  /** Called to broadcast an unfollow action */
  onUnfollow?: (bapId: string) => Promise<FollowResult>
  /** Called after a successful follow/unfollow */
  onToggled?: (following: boolean, result: FollowResult) => void
  /** Called on error */
  onError?: (error: Error) => void
}

export interface UseFollowReturn {
  /** Whether the current user is following the target */
  following: boolean
  /** Whether the user is hovering over the button */
  isHovering: boolean
  /** Set the hovering state */
  setIsHovering: (hovering: boolean) => void
  /** Current action state */
  actionState: FollowState
  /** Whether a follow/unfollow action is in progress */
  isLoading: boolean
  /** Whether the unfollow UI should show */
  showUnfollow: boolean
  /** The current label to display */
  currentLabel: string
  /** Handle the follow/unfollow click */
  handleClick: () => Promise<void>
}

// ---------------------------------------------------------------------------
// Hook
// ---------------------------------------------------------------------------

export function useFollow({
  bapId,
  isFollowing: initialFollowing = false,
  onFollow,
  onUnfollow,
  onToggled,
  onError,
  labels = {},
}: UseFollowOptions & {
  labels?: {
    follow?: string
    following?: string
    unfollow?: string
  }
}): UseFollowReturn {
  const [following, setFollowing] = useState(initialFollowing)
  const [isHovering, setIsHovering] = useState(false)
  const [actionState, setActionState] = useState<FollowState>("idle")

  const followLabel = labels.follow ?? "Follow"
  const followingLabel = labels.following ?? "Following"
  const unfollowLabel = labels.unfollow ?? "Unfollow"

  const isLoading = actionState === "following" || actionState === "unfollowing"

  const showUnfollow = following && isHovering && !!onUnfollow

  const currentLabel = isLoading
    ? following
      ? "Unfollowing..."
      : "Following..."
    : showUnfollow
      ? unfollowLabel
      : following
        ? followingLabel
        : followLabel

  const handleClick = useCallback(async () => {
    if (isLoading) return

    const wasFollowing = following

    if (wasFollowing) {
      if (!onUnfollow) return

      setActionState("unfollowing")

      try {
        const result = await onUnfollow(bapId)

        if (result.error) {
          onError?.(new Error(result.error))
        } else {
          setFollowing(false)
          onToggled?.(false, result)
        }
      } catch (err) {
        const error = err instanceof Error ? err : new Error("Failed to unfollow")
        onError?.(error)
      } finally {
        setActionState("idle")
      }
    } else {
      setActionState("following")

      try {
        const result = await onFollow(bapId)

        if (result.error) {
          onError?.(new Error(result.error))
        } else {
          setFollowing(true)
          onToggled?.(true, result)
        }
      } catch (err) {
        const error = err instanceof Error ? err : new Error("Failed to follow")
        onError?.(error)
      } finally {
        setActionState("idle")
      }
    }
  }, [isLoading, following, bapId, onFollow, onUnfollow, onToggled, onError])

  return {
    following,
    isHovering,
    setIsHovering,
    actionState,
    isLoading,
    showUnfollow,
    currentLabel,
    handleClick,
  }
}
